// 1. PALAVRAS FORTES (Específicas)
const strongKeywords = [
  "inss", "previdência", "previdencia", "loas", "bpc", 
  "revisão da vida toda", "direito previdenciário", "benefício previdenciário", "auxílio-doença"
];

// 2. PALAVRAS FRACAS (Agora mais focadas)
const weakKeywords = [
  "aposentadoria", "aposentado", "pensão"
];

// 3. BLACKLIST (Lista Negra expandida com saúde, dieta e comportamento)
const negativeKeywords = [
  // Esportes e Famosos
  "futebol", "jogador", "técnico", "esporte", "campeonato", "novela", 
  "filme", "ator", "atriz", "cinema", "show", "música", "fofoca", "bbb",
  // Saúde e Culinária
  "alimento", "superalimento", "dieta", "nutrição", "receita", "saúde mental",
  "emagrecer", "calorias", "prato", "gastronomia", "chef"
];

const filteredItems = [];

// Função auxiliar para buscar palavras exatas (evita que "inss" aprove "inssuportável")
function containsWord(text, wordList) {
  return wordList.some(word => {
    // Cria uma regra que exige que a palavra esteja "solta" no texto
    const regex = new RegExp(`\\b${word}\\b`, 'i'); 
    return regex.test(text);
  });
}

for (const item of $input.all()) {
  const title = (item.json.title || "").toLowerCase();
  const content = (item.json.content || item.json.contentSnippet || item.json.description || "").toLowerCase();

  // Removemos a acentuação para a análise ficar ainda mais perfeita
  const textToAnalyze = (title + " " + content)
    .normalize('NFD').replace(/[\u0300-\u036f]/g, "");

  // Removemos acentos das nossas listas de palavras antes de testar
  const cleanNegatives = negativeKeywords.map(w => w.normalize('NFD').replace(/[\u0300-\u036f]/g, ""));
  const cleanStrong = strongKeywords.map(w => w.normalize('NFD').replace(/[\u0300-\u036f]/g, ""));
  const cleanWeak = weakKeywords.map(w => w.normalize('NFD').replace(/[\u0300-\u036f]/g, ""));

  // 1. Passa pela Blacklist?
  if (containsWord(textToAnalyze, cleanNegatives)) {
    continue; // Descarta imediatamente
  }

  // 2. Tem palavra Forte?
  const hasStrong = containsWord(textToAnalyze, cleanStrong);

  // 3. Tem palavra Fraca?
  const hasWeak = containsWord(textToAnalyze, cleanWeak);

  // Aprova apenas se for o assunto certo!
  if (hasStrong || hasWeak) {
    filteredItems.push(item);
  }
}

return filteredItems;

