// Array para guardar os itens formatados
const newItems = [];

for (const item of $input.all()) {
  try {
    // 1. Acessa o texto bruto que o Gemini gerou
    const rawText = item.json.candidates[0].content.parts[0].text;

    // 2. Converte a string (texto) em um Objeto JSON real
    const parsedData = JSON.parse(rawText);

    // 3. Substitui toda a bagunça do Google apenas pelos nossos dados limpinhos
    newItems.push({
      json: parsedData
    });

  } catch (error) {
    // Se por acaso a IA bugar e não retornar um JSON válido, salvamos o erro para não quebrar o fluxo
    newItems.push({
      json: {
        erro_no_parse: error.message,
        retorno_original: item.json
      }
    });
  }
}

// Retorna os dados limpos para os próximos nós do n8n
return newItems;
